const body      = $input.first().json?.body || {};
const userId    = body.userId    || null;
const articleId = body.articleId || null;
const vote      = parseInt(body.vote || '0', 10);

if (!userId)                        throw new Error('userId mancante');
if (!articleId)                     throw new Error('articleId mancante');
if (vote !== 1 && vote !== -1)      throw new Error('vote deve essere 1 (like) o -1 (dislike)');

console.log(`[BriefAI W4] Feedback ricevuto — userId=${userId} articleId=${articleId} vote=${vote}`);

return [{ json: { userId, articleId, vote } }];

const article = $input.first().json;
const params  = $('Extract Feedback Params').first().json;

if (!article || !article.uniqueKey) {
  throw new Error(`Articolo non trovato: ${params.articleId}`);
}

return [{ json: {
  userId:             params.userId,
  articleId:          params.articleId,
  vote:               params.vote,
  articleMacroTopics: article.macroTopics || [],
  articleSentiment:   article.sentiment   || 'Neutral',
  articleSource:      article.source      || ''
}}];

// ============================================================
// FEEDBACK LOOP ENGINE — BriefAI Workflow 4
// Ogni like/dislike aggiusta il peso dei macroTopics dell'articolo
// Pesi: range [0.0 – 2.4], step 0.2, default 1.0
// ============================================================

const MACRO_TOPICS = [
  'Intelligenza Artificiale', 'Cybersecurity', 'Business & Finanza',
  'Politica & Geopolitica', 'Startup & Innovazione', 'Software & Sviluppo',
  'Scienza & Ricerca', 'Energia & Ambiente', 'Economia & Mercati',
  'Social Media & Cultura', 'Salute & Medicina', 'Trasporti & Mobilità'
];

const profile = $input.first().json;
const meta    = $('Attach Article Metadata').first().json;

const STEP = 0.2;
const MIN  = 0.0;
const MAX  = 2.4;

// Usa i pesi esistenti o inizializza a 1.0 per tutti i macroTopics
const weights = profile.weights || Object.fromEntries(MACRO_TOPICS.map(t => [t, 1.0]));

const macroTopics = meta.articleMacroTopics || [];
const vote        = meta.vote;

// Aggiorna il peso per ogni macroTopic dell'articolo
const updatedTopics = {};
for (const topic of macroTopics) {
  const current = weights[topic] !== undefined ? weights[topic] : 1.0;
  const updated = parseFloat(
    Math.min(MAX, Math.max(MIN, current + vote * STEP)).toFixed(2)
  );
  weights[topic]       = updated;
  updatedTopics[topic] = { previous: current, new: updated };
}

// Gestione preferredSources:
// Se like, aggiungi la source alle preferite (se non c'è già)
const preferredSources = profile.preferredSources || [];
if (vote === 1 && meta.articleSource && !preferredSources.includes(meta.articleSource)) {
  preferredSources.push(meta.articleSource);
}

const feedbackSummary = {
  macroTopics:    macroTopics,
  updatedWeights: updatedTopics,
  delta:          parseFloat((vote * STEP).toFixed(2)),
  vote,
  source:         meta.articleSource
};

console.log(`[BriefAI W4] Pesi aggiornati — macroTopics=${JSON.stringify(macroTopics)} (vote=${vote})`);

return [{ json: {
  userId:           meta.userId,
  weights,
  preferredSources,
  updatedAt:        new Date().toISOString(),
  _feedbackSummary: feedbackSummary
}}];

// Log del risultato finale per debug
const summary = $('Compute Updated Weights').first().json._feedbackSummary;
console.log(`[BriefAI W4] Profilo salvato. Riepilogo:`, JSON.stringify(summary));
return $input.all();

